	}

	if len(unmapped) > 0 {
		warnings = append(warnings, TranslationWarning{
			GossKey:  "file",
			Resource: name,
			Category: WarnPartial,
			Message:  fmt.Sprintf("Goss specified %s — not yet supported natively", strings.Join(unmapped, ", ")),
		})
