12		"github.com/CosmoLabs-org/cosmo-smoke/internal/reporter"
13		"github.com/CosmoLabs-org/cosmo-smoke/internal/schema"
14	)
15	
16	// RunOptions controls test execution behavior.
17	type RunOptions struct {
18		Tags        []string
19		ExcludeTags []string
20		FailFast    bool
21		DryRun      bool
22		Timeout     time.Duration // per-test override (0 = use config)
23	}
24	
25	// SuiteResult holds the aggregate outcome.
26	type SuiteResult struct {
27		Project         string
28		Total           int
29		Passed          int
30		Failed          int
31		Skipped         int
32		AllowedFailures int
33		Duration        time.Duration
34		Tests           []TestResult
35	}
36	
37	// TestResult holds one test's outcome.
38	type TestResult struct {
39		Name           string
40		Passed         bool
41		Skipped        bool
42		AllowedFailure bool // true if test failed but allow_failure was set
43		Duration       time.Duration
44		Assertions     []AssertionResult
45		Error          error
46		Attempts       int // number of attempts made (1 = no retry)
47	}
48	
49	// Runner executes smoke tests from a config.
50	type Runner struct {
51		Config    *schema.SmokeConfig
52		Reporter  reporter.Reporter
53		ConfigDir string
54	}
55	
56	// Run executes all tests per the options and returns the suite result.
57	func (r *Runner) Run(opts RunOptions) (*SuiteResult, error) {
58		start := time.Now()
59	
60		// Run prerequisites
61		if len(r.Config.Prereqs) > 0 {
62			timeout := r.Config.Settings.Timeout.Duration
63			if timeout == 0 {
64				timeout = 30 * time.Second
65			}
66			results := CheckPrerequisites(r.Config.Prereqs, timeout)
67			for _, pr := range results {
68				r.Reporter.PrereqStart(pr.Name)
69				r.Reporter.PrereqResult(reporter.PrereqResultData{
70					Name:   pr.Name,
71					Passed: pr.Passed,
72					Output: pr.Output,
73					Hint:   pr.Hint,
74					Error:  pr.Error,
75				})
76			}
77			// Check for prereq failures
78			for _, pr := range results {
79				if !pr.Passed {
80					return nil, fmt.Errorf("prerequisite %q failed: %v", pr.Name, pr.Error)
81				}
82			}
83		}
84	
85		// Filter tests by tags
86		tests := filterTests(r.Config.Tests, opts.Tags, opts.ExcludeTags)
87	
88		suite := &SuiteResult{
89			Project: r.Config.Project,
90			Total:   len(tests),
91		}
92	
93		failFast := opts.FailFast || r.Config.Settings.FailFast
94	
95		if r.Config.Settings.Parallel && !failFast {
96			r.runParallel(tests, opts, suite)
97		} else {
98			r.runSequential(tests, opts, suite, failFast)
99		}
100	
101		suite.Duration = time.Since(start)
102	
103		// Report summary
104		r.Reporter.Summary(reporter.SuiteResultData{
105			Project:         suite.Project,
106			Total:           suite.Total,
107			Passed:          suite.Passed,
108			Failed:          suite.Failed,
109			Skipped:         suite.Skipped,
110			AllowedFailures: suite.AllowedFailures,
111			Duration:        suite.Duration,
112		})
113	
114		return suite, nil
115	}
116	
117	func (r *Runner) runSequential(tests []schema.Test, opts RunOptions, suite *SuiteResult, failFast bool) {
118		stopped := false
119		for _, t := range tests {
120			if stopped {
121				tr := TestResult{Name: t.Name, Skipped: true}
122				suite.Tests = append(suite.Tests, tr)
123				suite.Skipped++
124				r.Reporter.TestStart(t.Name)
125				r.Reporter.TestResult(reporter.TestResultData{Name: t.Name, Skipped: true})
126				continue
127			}
128	
129			tr := r.runTest(t, opts)
130			suite.Tests = append(suite.Tests, tr)
131			if tr.Passed {
132				suite.Passed++
133			} else if tr.Skipped {
134				suite.Skipped++
135			} else if tr.AllowedFailure {
136				suite.AllowedFailures++
137			} else {
138				suite.Failed++
139				if failFast {
140					stopped = true
141				}
142			}
143		}
144	}
145	
146	func (r *Runner) runParallel(tests []schema.Test, opts RunOptions, suite *SuiteResult) {
147		results := make([]TestResult, len(tests))
148		var wg sync.WaitGroup
149	
150		for i, t := range tests {
151			wg.Add(1)
152			go func(idx int, test schema.Test) {
153				defer wg.Done()
154				results[idx] = r.runTest(test, opts)
155			}(i, t)
156		}
157		wg.Wait()
158	
159		for _, tr := range results {
160			suite.Tests = append(suite.Tests, tr)
161			if tr.Passed {
162				suite.Passed++
163			} else if tr.Skipped {
164				suite.Skipped++
165			} else if tr.AllowedFailure {
166				suite.AllowedFailures++
167			} else {
168				suite.Failed++
169			}
170		}
171	}
172	
173	func (r *Runner) runTest(t schema.Test, opts RunOptions) TestResult {
174		if t.Retry == nil || t.Retry.Count <= 1 {
175			res := r.runTestOnce(t, opts)
176			if res.Attempts == 0 {
177				res.Attempts = 1
178			}
179			return res
180		}
181		var last TestResult
182		backoff := t.Retry.Backoff.Duration
183		for attempt := 1; attempt <= t.Retry.Count; attempt++ {
184			last = r.runTestOnce(t, opts)
185			if last.Passed {
186				last.Attempts = attempt
187				return last
188			}
189			if attempt < t.Retry.Count {
190				time.Sleep(backoff)
191				backoff *= 2
192			}
193		}
194		last.Attempts = t.Retry.Count
195		return last
196	}
197	
198	func (r *Runner) runTestOnce(t schema.Test, opts RunOptions) TestResult {
199		r.Reporter.TestStart(t.Name)
200		start := time.Now()
201	
202		if opts.DryRun {
203			tr := TestResult{Name: t.Name, Passed: true, Duration: time.Since(start)}
204			r.Reporter.TestResult(toReporterResult(tr))
205			return tr
206		}
207	
208		// Determine timeout
209		timeout := opts.Timeout
210		if timeout == 0 {
211			timeout = t.Timeout.Duration
212		}
213		if timeout == 0 {
214			timeout = r.Config.Settings.Timeout.Duration
215		}
216		if timeout == 0 {
217			timeout = 30 * time.Second
218		}
219	
220		// Run cleanup via defer
221		if t.Cleanup != "" {
222			defer func() {
223				ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
224				defer cancel()
225				c := exec.CommandContext(ctx, "sh", "-c", t.Cleanup)
226				c.Dir = r.ConfigDir
227				c.Run()
228			}()
229		}
230	
231		// Execute command
232		ctx, cancel := context.WithTimeout(context.Background(), timeout)
233		defer cancel()
234	
235		cmd := exec.CommandContext(ctx, "sh", "-c", t.Run)
236		cmd.Dir = r.ConfigDir
237		var stdout, stderr bytes.Buffer
238		cmd.Stdout = &stdout
239		cmd.Stderr = &stderr
240	
241		err := cmd.Run()
242		exitCode := 0
243		if err != nil {
244			if exitErr, ok := err.(*exec.ExitError); ok {
245				exitCode = exitErr.ExitCode()
246			} else {
247				tr := TestResult{
248					Name:           t.Name,
249					AllowedFailure: t.AllowFailure,
250					Duration:       time.Since(start),
251					Error:          err,
252				}
253				r.Reporter.TestResult(toReporterResult(tr))
254				return tr
255			}
256		}
257	
258		// Evaluate assertions
259		var assertions []AssertionResult
260		allPassed := true
261	
262		if t.Expect.ExitCode != nil {
263			a := CheckExitCode(exitCode, *t.Expect.ExitCode)
264			assertions = append(assertions, a)
265			if !a.Passed {
266				allPassed = false
267			}
268		}
269		if t.Expect.StdoutContains != "" {
270			a := CheckStdoutContains(stdout.String(), t.Expect.StdoutContains)
271			assertions = append(assertions, a)
272			if !a.Passed {
273				allPassed = false
274			}
275		}
276		if t.Expect.StdoutMatches != "" {
277			a := CheckStdoutMatches(stdout.String(), t.Expect.StdoutMatches)
278			assertions = append(assertions, a)
279			if !a.Passed {
280				allPassed = false
281			}
282		}
283		if t.Expect.StderrContains != "" {
284			a := CheckStderrContains(stderr.String(), t.Expect.StderrContains)
285			assertions = append(assertions, a)
286			if !a.Passed {
287				allPassed = false
288			}
289		}
290		if t.Expect.StderrMatches != "" {
291			a := CheckStderrMatches(stderr.String(), t.Expect.StderrMatches)
292			assertions = append(assertions, a)
293			if !a.Passed {
294				allPassed = false
295			}
296		}
297		if t.Expect.EnvExists != "" {
298			a := CheckEnvExists(t.Expect.EnvExists)
299			assertions = append(assertions, a)
