15		"github.com/spf13/cobra"
16	)
17	
18	var runCmd = &cobra.Command{
19		Use:   "run",
20		Short: "Run smoke tests",
21		Long:  "Execute smoke tests defined in .smoke.yaml",
22		RunE:  runSmoke,
23	}
24	
25	var (
26		configFile  string
27		tags        []string
28		excludeTags []string
29		format      string
30		failFast    bool
31		timeout     string
32		dryRun      bool
33		watch       bool
34	)
35	
36	func init() {
37		rootCmd.AddCommand(runCmd)
38		runCmd.Flags().StringVarP(&configFile, "file", "f", ".smoke.yaml", "Config file path")
39		runCmd.Flags().StringSliceVar(&tags, "tag", nil, "Include only tests with these tags")
40		runCmd.Flags().StringSliceVar(&excludeTags, "exclude-tag", nil, "Exclude tests with these tags")
41		runCmd.Flags().StringVar(&format, "format", "terminal", "Output format (terminal|json|junit|tap|prometheus)")
42		runCmd.Flags().BoolVar(&failFast, "fail-fast", false, "Stop on first failure")
43		runCmd.Flags().StringVar(&timeout, "timeout", "", "Per-test timeout override (e.g. 30s)")
44		runCmd.Flags().BoolVar(&dryRun, "dry-run", false, "List tests without running")
45		runCmd.Flags().BoolVar(&watch, "watch", false, "Re-run tests when files change (Ctrl+C to exit)")
46	}
47	
48	func runSmoke(cmd *cobra.Command, args []string) error {
49		cfg, err := schema.Load(configFile)
50		if err != nil {
51			return fmt.Errorf("loading config: %w", err)
52		}
53	
54		if err := schema.Validate(cfg); err != nil {
55			return fmt.Errorf("invalid config: %w", err)
56		}
57	
58		configDir := filepath.Dir(configFile)
59		if !filepath.IsAbs(configDir) {
60			cwd, _ := os.Getwd()
61			configDir = filepath.Join(cwd, configDir)
62		}
63	
64		// Create reporter
65		var rep reporter.Reporter
66		switch format {
67		case "json":
68			rep = reporter.NewJSON(os.Stdout)
69		case "junit":
70			rep = reporter.NewJUnit(os.Stdout)
71		case "tap":
72			rep = reporter.NewTAP(os.Stdout)
73		case "prometheus":
74			rep = reporter.NewPrometheus(os.Stdout)
75		default:
76			rep = reporter.NewTerminal(os.Stdout)
77		}
78	
79		// Parse timeout
80		var timeoutDur time.Duration
81		if timeout != "" {
82			timeoutDur, err = time.ParseDuration(timeout)
83			if err != nil {
84				return fmt.Errorf("invalid timeout %q: %w", timeout, err)
85			}
86		}
87	
88		r := &runner.Runner{
89			Config:    cfg,
90			Reporter:  rep,
91			ConfigDir: configDir,
92		}
93	
94		runOnce := func() error {
95			result, err := r.Run(runner.RunOptions{
96				Tags:        tags,
97				ExcludeTags: excludeTags,
98				FailFast:    failFast,
99				DryRun:      dryRun,
100				Timeout:     timeoutDur,
101			})
102			if err != nil {
103				return err
104			}
105			// In watch mode, don't exit process on failure — print marker and loop
106			if !watch && result.Failed > 0 {
107				os.Exit(1)
108			}
109			return nil
110		}
111	
112		if !watch {
113			return runOnce()
114		}
115	
116		return runWatch(configDir, configFile, runOnce)
117	}
118	
119	func runWatch(configDir, configFile string, runOnce func() error) error {
120		// Run once immediately
121		if err := runOnce(); err != nil {
122			fmt.Fprintf(os.Stderr, "initial run error: %v\n", err)
123		}
124	
125		w, err := fsnotify.NewWatcher()
126		if err != nil {
127			return fmt.Errorf("fsnotify: %w", err)
128		}
129		defer w.Close()
130	
131		if err := w.Add(configDir); err != nil {
132			return fmt.Errorf("watching %s: %w", configDir, err)
133		}
134	
135		fmt.Fprintln(os.Stderr, "👀 watching", configDir, "(Ctrl+C to exit)")
136	
137		sigCh := make(chan os.Signal, 1)
138		signal.Notify(sigCh, os.Interrupt, syscall.SIGTERM)
139	
140		// Debounce: coalesce rapid events into a single re-run
141		debounce := 500 * time.Millisecond
142		var timer *time.Timer
143	
144		trigger := func() {
145			fmt.Fprintln(os.Stderr, "\n🔁 change detected, re-running…")
146			if err := runOnce(); err != nil {
147				fmt.Fprintf(os.Stderr, "run error: %v\n", err)
148			}
149		}
150	
151		for {
152			select {
153			case ev, ok := <-w.Events:
154				if !ok {
155					return nil
156				}
157				// Ignore chmod-only events
158				if !isRelevantEvent(ev.Op) {
159					continue
160				}
161				if timer != nil {
162					timer.Stop()
163				}
164				timer = time.AfterFunc(debounce, trigger)
165			case err, ok := <-w.Errors:
166				if !ok {
167					return nil
168				}
169				fmt.Fprintf(os.Stderr, "watch error: %v\n", err)
170			case <-sigCh:
171				fmt.Fprintln(os.Stderr, "\n✋ stopping watcher")
172				return nil
173			}
174		}
175	}
