			return fmt.Errorf("invalid timeout %q: %w", timeout, err)
		}
	}

	r := &runner.Runner{
		Config:    cfg,
		Reporter:  rep,
		ConfigDir: configDir,
	}

	runOnce := func() error {
		result, err := r.Run(runner.RunOptions{
			Tags:        tags,
			ExcludeTags: excludeTags,
			FailFast:    failFast,
			DryRun:      dryRun,
			Timeout:     timeoutDur,
		})
		if err != nil {
			return err
		}
		// In watch mode, don't exit process on failure — print marker and loop
		if !watch && result.Failed > 0 {
			os.Exit(1)
		}
		return nil
